$$
\text{For } k = 1, 2, \dots, 10, \text{ we have}
$$
\frac{k(k+3)+\sqrt{2}}{(k+1)^2-2} = \frac{(k+1+\sqrt{2})(k+2-\sqrt{2})}{(k+1+\sqrt{2})(k+1-\sqrt{2})} = \frac{k+2-\sqrt{2}}{k+1-\sqrt{2}}
$$
\text{Therefore, we obtain}
$$
\begin{aligned}
\frac{(1 \times 4 + \sqrt{2})(2 \times 5 + \sqrt{2}) \cdots (10 \times 13 + \sqrt{2})}{(2 \times 2 - 2)(3 \times 3 - 2) \cdots (11 \times 11 - 2)} &= \frac{3 - \sqrt{2}}{2 - \sqrt{2}} \cdot \frac{4 - \sqrt{2}}{3 - \sqrt{2}} \cdots \frac{12 - \sqrt{2}}{11 - \sqrt{2}} \\
&= \frac{12 - \sqrt{2}}{2 - \sqrt{2}} = 11 + 5\sqrt{2}
\end{aligned}
$$
\text{for the desired answer.}
